// ---- Pillar 1: Trend Monitor — Google Trends unofficial JSON → Supabase ----
// Checks interest-over-time for Markexis keyword clusters.
// No API key needed. Strips the )]}' XSSI prefix Google adds.
// Architecture: parallel fetches for all clusters, score stored in keywords table.
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;

const CLUSTERS = [
  { name: 'latam_market_entry', keyword: 'latam market entry', geo: 'US' },
  { name: 'ai_marketing',       keyword: 'ai marketing strategy', geo: 'US' },
  { name: 'gtm_strategy',       keyword: 'go-to-market strategy b2b', geo: 'US' },
  { name: 'latam_mexico',       keyword: 'mexico market entry', geo: 'US' },
  { name: 'latam_brazil',       keyword: 'brazil market expansion', geo: 'US' },
];

async function fetchTrend(kw, geo) {
  // Google Trends interest-over-time — past 3 months
  const req = JSON.stringify({ comparisonItem: [{ keyword: kw, geo, time: 'today 3-m' }], category: 0, property: '' });
  const url = `https://trends.google.com/trends/api/explore?hl=en-US&tz=300&req=${encodeURIComponent(req)}&ots=${Date.now()}&authuser=0`;
  try {
    const raw = await this.helpers.httpRequest({ method: 'GET', url, json: false, timeout: 20000 });
    // Strip XSSI prefix and parse
    const json = JSON.parse(String(raw).replace(/^\)\]\}'\n/, ''));
    const widget = json.widgets?.find(w => w.type === 'TIMESERIES' || w.id === 'TIMESERIES');
    return widget?.request?.requestOptions || null;
  } catch { return null; }
}

async function fetchTrendData(token, geo) {
  if (!token) return null;
  try {
    const req = JSON.stringify({ time: 'today 3-m', resolution: 'WEEK', locale: 'en-US', comparisonItem: [{ geo: { country: geo }, complexKeywordsRestriction: { keyword: [{ type: 'BROAD', value: token }] }], requestOptions: { property: '', backend: 'CM', category: 0 }, userConfig: { userType: 'USER_TYPE_SCRAPER' } });
    const raw = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://trends.google.com/trends/api/widgetdata/multiline?hl=en-US&tz=300&req=${encodeURIComponent(req)}&token=${encodeURIComponent(token)}&user_gp=&authuser=0`,
      json: false, timeout: 20000
    });
    const data = JSON.parse(String(raw).replace(/^\)\]\}'\n/, ''));
    const points = data.default?.timelineData || [];
    if (!points.length) return null;
    const recent = points.slice(-4); // last 4 weeks
    const avg = recent.reduce((s, p) => s + (p.value?.[0] || 0), 0) / recent.length;
    const prev = points.slice(-8, -4);
    const prevAvg = prev.reduce((s, p) => s + (p.value?.[0] || 0), 0) / Math.max(prev.length, 1);
    return { current: Math.round(avg), previous: Math.round(prevAvg), change_pct: prevAvg ? Math.round(((avg - prevAvg) / prevAvg) * 100) : 0 };
  } catch { return null; }
}

// Fetch all clusters in parallel (rate-limit: 1s gap between requests)
const results = [];
for (const cluster of CLUSTERS) {
  await new Promise(r => setTimeout(r, 1200)); // 1.2s between requests to avoid rate-limit
  const explore = await fetchTrend.call(this, cluster.keyword, cluster.geo);
  const trend = await fetchTrendData.call(this, explore, cluster.geo);
  results.push({
    cluster: cluster.name,
    keyword: cluster.keyword,
    trend_current: trend?.current || null,
    trend_previous: trend?.previous || null,
    trend_change_pct: trend?.change_pct || null,
    rising: trend ? trend.change_pct > 20 : false,
    checked_at: new Date().toISOString()
  });
}

// Store rising signals in Supabase keywords table as priority_score updates
const rising = results.filter(r => r.rising);
if (rising.length && ENV.SUPABASE_URL) {
  await Promise.allSettled(rising.map(r =>
    this.helpers.httpRequest({
      method: 'PATCH',
      url: `${ENV.SUPABASE_URL}/rest/v1/keywords?cluster=eq.${encodeURIComponent('cluster_1_' + r.cluster.split('_')[0])}`,
      headers: { apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ priority_score: 10 }),
      json: false, timeout: 10000
    }).catch(() => null)
  ));
}

return [{ json: { ok: true, clusters: results.length, rising: rising.length, results } }];
